"use server";
import { z } from "zod";
import { getSupabaseServerClient } from "@/lib/supabase/server";
import { revalidatePath } from "next/cache";

const MessageSchema = z.object({
  message: z.string().min(1).max(2000),
});

export async function sendMessageAction(formData: FormData) {
  const raw = {
    message: String(formData.get("message") || ""),
  };
  const parsed = MessageSchema.safeParse(raw);
  if (!parsed.success) {
    return { ok: false, error: "Invalid input" } as const;
  }
  const supabase = await getSupabaseServerClient();
  const { data: userData } = await supabase.auth.getUser();
  const user = userData.user;
  if (!user) {
    return { ok: false, error: "Not authenticated" } as const;
  }
  const meta: any = user.user_metadata || {};
  const displayName = (meta.full_name || meta.name || (user.email ? String(user.email).split("@")[0] : "User")).toString();
  const email = user.email || null;
  const avatarUrl = (meta.avatar_url || meta.picture || null) as string | null;
  const { error } = await supabase.from("messages").insert({
    sender_user_id: user.id,
    name: displayName,
    email,
    avatar_url: avatarUrl,
    message: parsed.data.message,
  });
  if (error) {
    return { ok: false, error: error.message } as const;
  }
  revalidatePath("/");
  return { ok: true } as const;
}
